func getRegistrationHashes(client tls_client.HttpClient) map[string]string {
	request, _ := http.NewRequest("GET", "https://www.instagram.com/accounts/signup/email/", nil)
	request.Header = getSafariHeaders()
	response, err := client.Do(request)
	if err != nil {
		return nil
	}
	hashes := parseHashes(response)
	if hashes == nil {
		return nil
	}
	return hashes
}

